144→    public function sendRefuseEmail($rec_pro_id, string $token)
145→    {
146→        $candidate_info = $this->getCandidateInfo($rec_pro_id);
147→        if (empty($candidate_info)) {
148→            throw new InternalException(__('my_api.resume_mail_service_fail3', ['rec_pro_ids' => $rec_pro_id]), 801);
149→        }
150→        // 发完邮件后，更新发送的状态，再没有再次投递前，避免重复发送
151→        $rec = RecruitmentProcessionMd::with('Resume:id,channel_id,expect_job_ids')->where('id', $rec_pro_id)->first();
152→        // $key 的位置 就是当前job吧， 我要在这个job的第5个位置加个1 ，表示已发送拒信邮件，再更新 RecruitmentProcessionMd
153→        // 获取关联的简历数据
154→        $resume = $rec->resume;
155→        $expectJobs = $resume->expect_job_ids;
156→        $hasSendRefuse = false;
157→        foreach ($expectJobs as $job) {
158→            // 匹配当前流程对应的job_id（使用字段索引1的位置）
159→            if ($job[2] == $rec->job_id) {
160→                if (count($job) >= 5 && $job[4] == 1) {
161→                    $hasSendRefuse = true;
162→                    info('[250328]拒信邮件已发送 这次不再发了: '.$rec_pro_id.' job_id: '.$rec->job_id.' expectJobs: '.my_json_encode($expectJobs));
163→                    break;
164→                }
165→            }
166→        }
167→        if (!$hasSendRefuse) {
168→            // 拒信发送时间点更改成两个工作日
169→            // 获取两个工作日后得日期
170→            $workDate = (new CalendarService())->getWorkDateAfterDays(2);
171→            $replace = $this->getRefuseMailReplace($candidate_info);
172→            config(['']);
173→            info('发送拒信邮件: '.$rec_pro_id.' 时间: '.$workDate.' 17:00:00'.' token: '.$token);
174→            $this->sendTimeNormalMail('refuse', $token, $replace, [], $workDate.' 17:00:00');
175→            // 更新并保存数据
176→            foreach ($expectJobs as &$job) {
177→                // 在第四个位置（索引3）追加状态标记
178→                // 如果已有标记则更新，没有则新增
179→                if ($job[2] == $rec->job_id) {
180→                    $job[4] = 1;
181→                    info('[250328]更新拒信发送状态: '.$rec_pro_id.' job_id: '.$rec->job_id.' expectJobs: '.my_json_encode($expectJobs));
182→                }
183→            }
184→            $resume->expect_job_ids = $expectJobs;
185→            $resume->save();
186→        }
187→    }
