134→            const params = {
135→                id: this.resumeData.target_id,
136→                result: result,
137→            }
138→
139→            if (result === 'pass') {
140→                this.isConfirm = true
141→                // this.showMessage('提交成功，2秒后关闭页面')
142→            } else {
143→                this.isReject = true
144→                // this.showMessage('提交成功，2秒后关闭页面')
145→            }
146→
147→            this.localOperated = true
148→            this.$store.dispatch(aTypes.AJAX_SDK, {
149→                url: SERVER_API_URL + 'web-api/recruitment-procession/offer-approval',
150→                params,
151→                success: () => {
152→                    this.showMessage(`${this.$t('t500')}`)
153→                    this.isConfirm = false
154→                    this.isReject = false
155→
156→                    setTimeout(() => {
157→                        this.closeWindow()
158→                    }, 2000)
159→                },
160→                failure: () => {
161→                    this.isConfirm = false
162→                    this.isReject = false
163→                    this.localOperated = false
164→                },
165→            })
166→        },
167→
168→        closeWindow() {
169→            window.open('about:blank', '_self').close()
170→        },
171→    },
172→}
173→</script>
